355	fn extractGridLineSlice(alloc: std.mem.Allocator, pane_state: anytype, absolute_y: u32, start_x: u32, end_x: u32) ![]u8 {
356	    const grid = &pane_state.screen.grid;
357	    const total_lines = grid.hsize + grid.rows;
358	    if (absolute_y >= total_lines) return try alloc.dupe(u8, "");
359	
360	    const line = if (absolute_y < grid.hsize)
361	        grid.getHistoryLine(absolute_y)
362	    else
363	        grid.getLine(absolute_y - grid.hsize);
364	
365	    const max_x = @min(end_x, grid.cols -| 1);
366	    if (start_x > max_x) return try alloc.dupe(u8, "");
367	
368	    var buf: std.ArrayListAligned(u8, null) = .empty;
369	    defer buf.deinit(alloc);
370	    var x = start_x;
371	    while (x <= max_x) : (x += 1) {
372	        const cell = line.getCell(x);
373	        const ch: u8 = if (cell.codepoint == 0)
374	            ' '
375	        else if (cell.codepoint < 0x80)
376	            @truncate(cell.codepoint)
377	        else
378	            '?';
379	        try buf.append(alloc, ch);
380	    }
381	
382	    while (buf.items.len > 0 and buf.items[buf.items.len - 1] == ' ') {
383	        _ = buf.pop();
384	    }
385	    return try buf.toOwnedSlice(alloc);
386	}
