18	
19	/// Server state.
20	pub const Server = struct {
21	    listen_fd: std.c.fd_t,
22	    socket_path: []const u8,
23	    sessions: std.ArrayListAligned(*Session, null),
24	    clients: std.ArrayListAligned(ClientConnection, null),
25	    default_session: ?*Session,
26	    choose_tree_state: ?ChooseTreeState,
27	    paste_stack: PasteStack,
28	    session_loop: SessionLoop,
29	    binding_manager: binding_mod.BindingManager,
30	    global_default_shell: ?[:0]u8,
31	    config_file: ?[]const u8,
32	    running: bool,
33	    allocator: std.mem.Allocator,
34	
35	    pub const ClientConnection = struct {
36	        fd: std.c.fd_t,
37	        session: ?*Session,
38	        identified: bool,
39	        choose_tree_state: ?ChooseTreeState,
40	    };
41	
42	    pub fn init(alloc: std.mem.Allocator, socket_path: []const u8) !Server {
43	        var bm = binding_mod.BindingManager.init(alloc);
44	        try bm.setupDefaults();
45	
46	        return .{
47	            .listen_fd = -1,
48	            .socket_path = try alloc.dupe(u8, socket_path),
49	            .sessions = .empty,
50	            .clients = .empty,
51	            .default_session = null,
52	            .choose_tree_state = null,
53	            .paste_stack = PasteStack.init(alloc),
54	            .session_loop = SessionLoop.init(alloc),
55	            .binding_manager = bm,
56	            .global_default_shell = null,
57	            .config_file = null,
58	            .running = false,
59	            .allocator = alloc,
60	        };
61	    }
62	
63	    pub fn deinit(self: *Server) void {
64	        self.stop();
65	        for (self.sessions.items) |session| {
66	            session.deinit();
67	        }
68	        self.sessions.deinit(self.allocator);
69	        for (self.clients.items) |*client| {
70	            if (client.choose_tree_state) |*state| {
71	                state.deinit();
72	            }
73	            if (client.fd >= 0) _ = std.c.close(client.fd);
74	        }
75	        self.clients.deinit(self.allocator);
76	        if (self.choose_tree_state) |*state| {
77	            state.deinit();
78	        }
79	        self.paste_stack.deinit();
80	        self.session_loop.deinit();
81	        self.binding_manager.deinit();
82	        if (self.global_default_shell) |shell| self.allocator.free(shell);
83	        self.allocator.free(self.socket_path);
84	    }
85	
86	    pub fn listen(self: *Server) !void {
87	        try self.ensureSocketDir();
88	        self.removeStaleSocket();
89	
90	        const fd = std.c.socket(std.c.AF.UNIX, std.c.SOCK.STREAM, 0);
91	        if (fd < 0) return error.SocketFailed;
